import React, { useState, useEffect } from 'react';
import {
  Box,
  Paper,
  TextField,
  Button,
  Typography,
  Link,
  Alert,
  CircularProgress,
  Container,
  InputAdornment,
  IconButton
} from '@mui/material';
import {
  Visibility,
  VisibilityOff,
  Email,
  Lock
} from '@mui/icons-material';
import { Link as RouterLink } from 'react-router-dom';
import { toast } from 'react-toastify';
import { useAuth } from '../../contexts/AuthContext';

// Importando os SVGs
import btcLogo from '../../assets/crypto_logos/btc.svg';
import ethLogo from '../../assets/crypto_logos/eth.svg';
import ltcLogo from '../../assets/crypto_logos/ltc.svg';
// Adicione mais importações de logos conforme necessário

const Login = () => {
  const { login } = useAuth();
  const [formData, setFormData] = useState({
    email: '',
    password: ''
  });
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [displayText, setDisplayText] = useState('');
  const [isTyping, setIsTyping] = useState(true);
  const [showDots, setShowDots] = useState(false);

  const fullText = 'Nautilus Automação';
  const typingSpeed = 150;
  const pauseTime = 10000;

  // Array de logos SVG importados
  const cryptoLogos = [
    btcLogo,
    ethLogo,
    ltcLogo,
    // Adicione mais variáveis de logos importados aqui
  ];

  // Array extenso de símbolos de criptomoedas e blockchain
  const cryptoSymbols = [
    // Símbolos principais de criptomoedas
    '₿', 'Ξ', '⟠', 'Ł', '◊', '⧫', '◈', '◇', '⬟', '⬢', '⬡', '⬠',
    // Símbolos matemáticos e geométricos relacionados
    '⟐', '⟡', '⟢', '⟣', '⟤', '⟥', '⟦', '⟧', '⟨', '⟩', '⟪', '⟫', '⟬', '⟭',
    // Símbolos de moedas e financeiros
    '¤', '₳', '₴', '₵', '₶', '₷', '₸', '₹', '₺', '₻', '₼', '₽', '₾', '₿',
    // Símbolos de blockchain e tecnologia
    '⬢', '⬡', '⬠', '⬟', '⬞', '⬝', '⬜', '⬛', '⭐', '⭑', '⭒', '⭓', '⭔', '⭕',
    // Símbolos geométricos avançados
    '◆', '◇', '◈', '◉', '◊', '○', '◌', '◍', '◎', '●', '◐', '◑', '◒', '◓',
    // Símbolos de setas e direcionais
    '↗', '↘', '↙', '↖', '↕', '↔', '⇄', '⇅', '⇆', '⇇', '⇈', '⇉', '⇊', '⇋',
    // Símbolos de estrelas e formas
    '★', '☆', '✦', '✧', '✩', '✪', '✫', '✬', '✭', '✮', '✯', '✰', '✱', '✲',
    // Símbolos de tecnologia e digital
    '⚡', '⚙', '⚛', '⚜', '⚝', '⚞', '⚟', '⚠', '⚡', '⚢', '⚣', '⚤', '⚥', '⚦',
    // Símbolos adicionais de criptomoedas conhecidas
    'Ð', 'Ł', 'Ξ', '₳', 'Ⱥ', 'Ƀ', 'Ȼ', 'Đ', 'Ɇ', 'Ƒ', 'Ǥ', 'Ħ', 'Ɨ', 'Ɉ',
    // Símbolos de redes e conexões
    '⌘', '⌬', '⌭', '⌮', '⌯', '⌰', '⌱', '⌲', '⌳', '⌴', '⌵', '⌶', '⌷', '⌸',
    // Símbolos de segurança e criptografia
    '🔐', '🔑', '🔒', '🔓', '🔔', '🔕', '🔖', '🔗', '🔘', '🔙', '🔚', '🔛', '🔜', '🔝',
    // Símbolos de gráficos e análise
    '📈', '📉', '📊', '📋', '📌', '📍', '📎', '📏', '📐', '📑', '📒', '📓', '📔', '📕'
  ];

  useEffect(() => {
    let timeoutId;
    let currentIndex = 0;

    const typeText = () => {
      if (currentIndex <= fullText.length) {
        setDisplayText(fullText.slice(0, currentIndex));
        currentIndex++;
        timeoutId = setTimeout(typeText, typingSpeed);
      } else {
        setIsTyping(false);
        setShowDots(true);
        timeoutId = setTimeout(() => {
          setShowDots(false);
          setIsTyping(true);
          setDisplayText('');
          currentIndex = 0;
          typeText();
        }, pauseTime);
      }
    };

    typeText();

    return () => {
      if (timeoutId) {
        clearTimeout(timeoutId);
      }
    };
  }, []);

  // Função para gerar logos flutuantes (revisada para usar isSvgEffective)
  const generateFloatingSymbols = () => {
    const symbols = [];
    const numSymbols = 75;

    // Adicionando uma verificação para garantir que cryptoLogos seja usado se tiver itens.
    // const isSvgEffective = Array.isArray(cryptoLogos) && cryptoLogos.length > 0 && cryptoLogos.every(item => typeof item === 'string');
    const isSvgEffective = false; // Forçando o uso de cryptoSymbols para teste
    const logosToUse = isSvgEffective 
                         ? cryptoLogos 
                         : (Array.isArray(cryptoSymbols) ? cryptoSymbols : []);

    if (logosToUse.length === 0) return null; 

    for (let i = 0; i < numSymbols; i++) {
      const logoSrcOrSymbol = logosToUse[Math.floor(Math.random() * logosToUse.length)];
      const delay = Math.random() * 20; 
      const duration = 20 + Math.random() * 15; 
      const size = 30 + Math.random() * 40; 
      const initialLeft = Math.random() * 100; 
      const opacity = 0.3 + Math.random() * 0.5; 

      symbols.push(
        <Box
          key={`crypto-logo-${i}`}
          sx={{
            position: 'absolute',
            bottom: `-${size}px`, 
            left: `${initialLeft}vw`, 
            width: `${size}px`,
            height: `${size}px`,
            opacity: opacity,
            animation: `moveUp ${duration}s linear infinite`,
            animationDelay: `${delay}s`,
            userSelect: 'none',
            pointerEvents: 'none',
            zIndex: 0, 
            transform: 'translateX(-50%)', 
          }}
        >
          {isSvgEffective ? (
            <img src={logoSrcOrSymbol} alt="crypto logo" style={{ width: '100%', height: '100%' }} />
          ) : (
            <Typography sx={{ fontSize: `${size}px`, color: '#1976d2' }}>{logoSrcOrSymbol}</Typography>
          )}
        </Box>
      );
    }
    return symbols;
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
    // Limpar erro quando o usuário começar a digitar
    if (error) setError('');
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    // Validação básica
    if (!formData.email || !formData.password) {
      setError('Todos os campos são obrigatórios');
      setLoading(false);
      return;
    }

    // Validação simples de email
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(formData.email)) {
      setError('Formato de email inválido');
      setLoading(false);
      return;
    }

    try {
      const result = await login(formData.email, formData.password);

      if (result.success) {
        toast.success('Login realizado com sucesso!');
      } else {
        setError(result.message || 'Erro ao fazer login');
        toast.error(result.message || 'Erro ao fazer login');
      }
    } catch (error) {
      console.error('Erro no login:', error);
      setError('Erro ao fazer login. Tente novamente.');
      toast.error('Erro ao fazer login');
    } finally {
      setLoading(false);
    }
  };

  const togglePasswordVisibility = () => {
    setShowPassword(!showPassword);
  };

  return (
    <Box
      sx={{
        position: 'relative',
        minHeight: '100vh',
        overflow: 'hidden',
        background: 'linear-gradient(135deg, #f5f7fa 0%, #c3cfe2 100%)'
      }}
    >
      {/* Background com símbolos flutuantes */}
      <Box
        sx={{
          position: 'fixed', // Mantém fixo para cobrir a tela toda
          top: 0,
          left: 0,
          width: '100vw', // Usa vw para largura total da viewport
          height: '100vh', // Usa vh para altura total da viewport
          zIndex: 0, // Garante que está atrás do conteúdo
          overflow: 'hidden', // Essencial para não criar barras de rolagem
          pointerEvents: 'none' // Para não interferir com cliques no formulário
        }}
      >
        {generateFloatingSymbols()}
      </Box>

      {/* CSS para animações */}
      <style>
        {`
          @keyframes blink {
            0%, 50% { opacity: 1; }
            51%, 100% { opacity: 0; }
          }
          @keyframes blinkDots {
            0%, 33% { opacity: 1; }
            34%, 66% { opacity: 0.5; }
            67%, 100% { opacity: 0; }
          }
          @keyframes moveUp {
            0% {
              transform: translateY(0px) translateX(-50%) rotate(0deg); 
              opacity: 0.3;
            }
            50% {
              opacity: 0.8;
            }
            100% {
              transform: translateY(-110vh) translateX(-50%) rotate(360deg); 
              opacity: 0.1;
            }
          }
        `}
      </style>

      <Container maxWidth="sm" sx={{ position: 'relative', zIndex: 1 }}>
        <Box
          sx={{
            minHeight: '100vh',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            py: 4
          }}
        >
          <Paper
            elevation={8}
            sx={{
              p: 4,
              width: '100%',
              maxWidth: 400,
              bgcolor: 'rgba(255, 255, 255, 0.95)',
              borderRadius: 2,
              backdropFilter: 'blur(10px)'
            }}
          >
            {/* Logo/Título */}
            <Box sx={{ textAlign: 'center', mb: 4 }}>
              <Typography
                variant="h5"
                component="h1"
                sx={{
                  fontWeight: 'bold',
                  color: '#1976d2', // Cor azul
                  mb: 1,
                  minHeight: '2rem', // Altura mínima para evitar saltos
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  fontSize: '1.5rem',
                  whiteSpace: 'nowrap'
                }}
              >
                {displayText}
                {isTyping && (
                  <Box
                    component="span"
                    sx={{
                      display: 'inline-block',
                      width: '2px',
                      height: '1.2em',
                      backgroundColor: '#1976d2',
                      marginLeft: '2px',
                      animation: 'blink 1s infinite'
                    }}
                  />
                )}
                {showDots && (
                  <Box
                    component="span"
                    sx={{
                      color: '#1976d2',
                      marginLeft: '8px',
                      animation: 'blinkDots 1.5s infinite'
                    }}
                  >
                    ...
                  </Box>
                )}
              </Typography>
              <Typography
                variant="subtitle1"
                color="text.secondary"
              >
                Faça login em sua conta
              </Typography>
            </Box>

            {/* Formulário */}
            <Box component="form" onSubmit={handleSubmit}>
              {error && (
                <Alert severity="error" sx={{ mb: 2 }}>
                  {error}
                </Alert>
              )}

              <TextField
                fullWidth
                name="email"
                label="Email"
                type="email"
                value={formData.email}
                onChange={handleChange}
                margin="normal"
                required
                autoComplete="email"
                autoFocus
                InputProps={{
                  startAdornment: (
                    <InputAdornment position="start">
                      <Email color="action" />
                    </InputAdornment>
                  ),
                }}
                sx={{
                  '& .MuiOutlinedInput-root': {
                    '&:hover fieldset': {
                      borderColor: '#1976d2', // Cor azul
                    },
                    '&.Mui-focused fieldset': {
                      borderColor: '#1976d2', // Cor azul
                    },
                  },
                  '& .MuiInputLabel-root.Mui-focused': {
                    color: '#1976d2', // Cor azul
                  },
                }}
              />

              <TextField
                fullWidth
                name="password"
                label="Senha"
                type={showPassword ? 'text' : 'password'}
                value={formData.password}
                onChange={handleChange}
                margin="normal"
                required
                autoComplete="current-password"
                InputProps={{
                  startAdornment: (
                    <InputAdornment position="start">
                      <Lock color="action" />
                    </InputAdornment>
                  ),
                  endAdornment: (
                    <InputAdornment position="end">
                      <IconButton
                        onClick={togglePasswordVisibility}
                        edge="end"
                        aria-label="toggle password visibility"
                      >
                        {showPassword ? <VisibilityOff /> : <Visibility />}
                      </IconButton>
                    </InputAdornment>
                  ),
                }}
                sx={{
                  '& .MuiOutlinedInput-root': {
                    '&:hover fieldset': {
                      borderColor: '#1976d2', // Cor azul
                    },
                    '&.Mui-focused fieldset': {
                      borderColor: '#1976d2', // Cor azul
                    },
                  },
                  '& .MuiInputLabel-root.Mui-focused': {
                    color: '#1976d2', // Cor azul
                  },
                }}
              />

              <Button
                type="submit"
                fullWidth
                variant="contained"
                disabled={loading}
                sx={{
                  mt: 3,
                  mb: 2,
                  py: 1.5,
                  fontSize: '1rem',
                  fontWeight: 'bold',
                  bgcolor: '#1976d2', // Cor azul
                  color: 'white',
                  '&:hover': {
                    bgcolor: '#1565c0', // Azul mais escuro no hover
                  },
                  '&:disabled': {
                    bgcolor: 'action.disabled',
                  },
                }}
              >
                {loading ? (
                  <CircularProgress size={24} color="inherit" />
                ) : (
                  'Entrar'
                )}
              </Button>

              {/* Link para registro */}
              <Box sx={{ textAlign: 'center', mt: 2 }}>
                <Typography variant="body2" color="text.secondary">
                  Não tem uma conta?{' '}
                  <Link
                    component={RouterLink}
                    to="/register"
                    sx={{
                      color: '#1976d2', // Cor azul
                      textDecoration: 'none',
                      fontWeight: 'bold',
                      '&:hover': {
                        textDecoration: 'underline',
                      },
                    }}
                  >
                    Registre-se
                  </Link>
                </Typography>
              </Box>
            </Box>
          </Paper>
        </Box>
      </Container>
    </Box>
  );
};

export default Login;
